1	import { useState } from "react";
2	import { View, Text, Input, Textarea, Picker } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, PRESET_DOMAINS } from "../../lib";
5	import ReminderCard from "../../components/reminder-card";
6	import "./index.scss";
7	
8	export default function ProfilePage() {
9	  const [profile, setProfile] = useState({
10	    name: "", goals: "", wakeTime: "07:00", sleepTime: "23:00", customPrompt: "",
11	  });
12	  const [inputs, setInputs] = useState<{ category: string; content: string }[]>([]);
13	  const [newInput, setNewInput] = useState({ category: "健身", content: "" });
14	  const [saved, setSaved] = useState(false);
15	  const [reminderEnabled, setReminderEnabled] = useState(false);
16	  const [reminderTime, setReminderTime] = useState("21:00");
17	  const [reminderDays, setReminderDays] = useState<number[]>([1, 2, 3, 4, 5, 6, 7]);
18	
19	  useDidShow(() => {
20	    apiFetch("/api/profile").then((data) => {
21	      if (data.profile) {
22	        setProfile({
23	          name: data.profile.name || "",
24	          goals: Array.isArray(data.profile.goals) ? data.profile.goals.join("\n") : "",
25	          wakeTime: data.profile.wakeTime || "07:00",
26	          sleepTime: data.profile.sleepTime || "23:00",
27	          customPrompt: data.profile.preferences?.customPrompt || "",
28	        });
29	        const reminder = data.profile.reminder || {};
30	        setReminderEnabled(reminder.enabled || false);
31	        setReminderTime(reminder.time || "21:00");
32	        setReminderDays(reminder.days || [1, 2, 3, 4, 5, 6, 7]);
33	      }
34	      if (data.inputs) setInputs(data.inputs);
35	    });
36	  });
37	
38	  async function saveProfile() {
39	    await apiFetch("/api/profile", {
40	      method: "POST",
41	      body: JSON.stringify({
42	        name: profile.name,
43	        goals: profile.goals.split("\n").filter((g) => g.trim()),
44	        wakeTime: profile.wakeTime,
45	        sleepTime: profile.sleepTime,
46	        customPrompt: profile.customPrompt,
47	      }),
48	    });
49	    setSaved(true);
50	    setTimeout(() => setSaved(false), 2000);
51	  }
52	
53	  const REMINDER_TEMPLATE_ID = "TEMPLATE_ID";
54	
55	  async function saveReminder(enabled: boolean, time: string, days: number[]) {
56	    await apiFetch("/api/profile", {
57	      method: "POST",
58	      body: JSON.stringify({ reminder: { enabled, time, days } }),
59	    });
60	  }
61	
62	  async function handleReminderToggle(value: boolean) {
63	    if (value) {
64	      try {
65	        const res: Record<string, string> = await (Taro as any).requestSubscribeMessage({
66	          tmplIds: [REMINDER_TEMPLATE_ID],
67	        });
68	        if (res[REMINDER_TEMPLATE_ID] !== "accept") {
69	          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
70	          return;
71	        }
72	      } catch {
73	        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
74	        return;
75	      }
76	    }
77	    setReminderEnabled(value);
78	    await saveReminder(value, reminderTime, reminderDays);
79	    Taro.showToast({
80	      title: value ? "每日提醒已开启" : "每日提醒已关闭",
81	      icon: "success",
82	    });
83	  }
84	
85	  async function handleReminderTimeChange(time: string) {
86	    setReminderTime(time);
87	    if (reminderEnabled) {
88	      await saveReminder(true, time, reminderDays);
89	    }
90	  }
91	
92	  function handleReminderDayToggle(day: number) {
93	    const newDays = reminderDays.includes(day)
94	      ? reminderDays.filter((d) => d !== day)
95	      : [...reminderDays, day];
96	    setReminderDays(newDays);
97	    if (reminderEnabled) {
98	      saveReminder(true, reminderTime, newDays);
99	    }
100	  }
101	
102	  async function addInput() {
103	    if (!newInput.content.trim()) return;
104	    await apiFetch("/api/profile/input", {
105	      method: "POST",
106	      body: JSON.stringify(newInput),
107	    });
108	    setInputs([...inputs, newInput]);
109	    setNewInput({ category: "健身", content: "" });
110	  }
111	
112	  return (
113	    <View className="page">
114	      <Text className="page-title">个人设置</Text>
115	      <Text className="page-subtitle">越了解你，越能精准辅助</Text>
116	
117	      <View className="card">
118	        <Text className="card-title">基本信息</Text>
119	        <View className="form-group">
120	          <Text className="form-label">你的名字/称号</Text>
121	          <Input className="form-input" placeholder="朕 / 陛下" value={profile.name} onInput={(e) => setProfile({ ...profile, name: e.detail.value })} />
122	        </View>
123	        <View className="form-row">
124	          <View className="form-group flex-1">
125	            <Text className="form-label">起床时间</Text>
126	            <Picker mode="time" value={profile.wakeTime} onChange={(e) => setProfile({ ...profile, wakeTime: e.detail.value })}>
127	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.wakeTime}</Text></View>
128	            </Picker>
129	          </View>
130	          <View className="form-group flex-1">
131	            <Text className="form-label">睡觉时间</Text>
132	            <Picker mode="time" value={profile.sleepTime} onChange={(e) => setProfile({ ...profile, sleepTime: e.detail.value })}>
133	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.sleepTime}</Text></View>
134	            </Picker>
135	          </View>
136	        </View>
137	      </View>
138	
139	      <View className="card">
140	        <Text className="card-title">你的目标</Text>
141	        <Textarea className="form-textarea" placeholder={"提升商业分析能力\n养成运动习惯\n扩大社交圈\n..."} value={profile.goals} onInput={(e) => setProfile({ ...profile, goals: e.detail.value })} />
142	      </View>
143	
144	      <View className="card">
145	        <Text className="card-title">AI 个性化提示词</Text>
146	        <Textarea className="form-textarea" placeholder={"用「陛下」称呼我\n关注商业和管理领域\n多推荐前沿科技内容"} value={profile.customPrompt} onInput={(e) => setProfile({ ...profile, customPrompt: e.detail.value })} />
147	      </View>
148	
149	      <View className="save-btn" onClick={saveProfile}>
150	        <Text>{saved ? "已保存 ✓" : "保存设置"}</Text>
151	      </View>
152	
153	      <ReminderCard
154	        enabled={reminderEnabled}
155	        time={reminderTime}
156	        days={reminderDays}
157	        onToggle={handleReminderToggle}
158	        onTimeChange={handleReminderTimeChange}
159	        onDayToggle={handleReminderDayToggle}
160	      />
161	
162	      <View className="card">
163	        <Text className="card-title">个性化需求</Text>
164	        <View style={{ marginBottom: "20rpx" }}>
165	          {inputs.map((pi, i) => (
166	            <Text key={i} className="input-tag">{pi.category}: {pi.content}</Text>
167	          ))}
168	        </View>
169	        <View className="input-row">
170	          <Picker mode="selector" range={PRESET_DOMAINS.map(d => d.name)} value={PRESET_DOMAINS.findIndex(d => d.name === newInput.category)} onChange={(e) => setNewInput({ ...newInput, category: PRESET_DOMAINS[+e.detail.value].name })}>
171	            <View className="form-input" style={{ width: "160rpx", display: "flex", alignItems: "center" }}><Text>{newInput.category}</Text></View>
172	          </Picker>
173	          <Input className="form-input" style={{ flex: 1 }} placeholder="描述你的个性化需求..." value={newInput.content} onInput={(e) => setNewInput({ ...newInput, content: e.detail.value })} onConfirm={addInput} />
174	          <Text className="add-btn" onClick={addInput}>添加</Text>
175	        </View>
176	      </View>
177	    </View>
178	  );
179	}
